INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('2EZvvQ9', 'Ngô Phương Thảo', 'ngophthao95@gmail.com', 'Business Analyst', 'FPT Software', 'Information Technology', '1. Một số lời chia sẻ về chuyên môn cho bạn nào quan tâm đến IT Business Analyst.
2. Chia sẻ một số phương pháp vượt qua khủng hoảng tâm lý, như rối loạn lo âu hoặc trầm cảm, từ chính trải nghiệm cá nhân của mình. Cách giữ được sự hài lòng và cảm giác đủ đầy với cuộc sống, dù ở bất kỳ giai đoạn nào.
3. Cách bắt đầu lại (và làm tốt hơn) sau những thay đổi lớn trong công việc, mối quan hệ hay môi trường sống.
4. Duy trì niềm đam mê thể thao.', '1. Cách chủ động xây dựng lộ trình nghề nghiệp phù hợp cho IT Business Analyst trong thời đại AI, đặc biệt khi mình có xu hướng gắn bó lâu dài với tổ chức (như hiện tại là FPT).
2. Tiếp cận nguồn thông tin về các khóa học hoặc chương trình trao đổi ngắn hạn quốc tế được tài trợ, nhất là ở châu Âu hoặc Mỹ, để vừa phục vụ cho sự nghiệp, vừa mở rộng trải nghiệm.
3. Học cách đạt được sự thịnh vượng tài chính phù hợp với tính cách cá nhân, đồng thời xóa bỏ những rào cản tâm lý không lành mạnh liên quan đến tiền bạc.
4. Tìm hiểu các phương pháp chăm sóc sức khỏe thân – tâm – trí để giữ cân bằng giữa nhịp sống nhanh và yêu cầu cao của công việc.', 'Mình là một “tổ hợp” khá hài hòa giữa việc gắn bó với những điều quen thuộc, cùng lòng tò mò háo hức khám phá thế giới, luôn muốn học hỏi, trải nghiệm và không ngừng phát triển mỗi ngày, nhưng vẫn luôn chú trọng nhất vào việc xây dựng một nội tâm vững vàng và bình ổn từ bên trong.
Mình là người không thoải mái thể hiện hay bày tỏ quá nhiều trước đám đông. Có thể vì khi đưa ra một lời khuyên nào đó, mình thường nghĩ rằng điều đúng với mình chưa chắc đã đúng với người khác, có thể họ sẽ có cách tốt hơn, bởi mỗi người đều có hành trình riêng, nơi họ chính là “người thầy” và “người tư vấn” hiểu rõ bản thân nhất. Dù vậy, mình lại rất cởi mở khi trò chuyện thân tình 1:1 hoặc trong nhóm nhỏ, nơi mình hiểu hơn về người đối diện. Và mình luôn hy vọng, không phải những gì mình nói mà chính cách mình sống và mỉm cười có thể truyền cảm hứng, góp phần tạo nên những thay đổi tích cực trong cuộc sống của những người mình gặp.', 'https://storage.tally.so/private/1.JPG?id=eNKE80&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6ImVOS0U4MCIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc2MjQxMDU3MX0.OlPKrfQCiDkkI1iS6n3JoihQ_RD3KMyozmvEv4Zarzk&signature=20682c8c822db879243b0a1008610f70f4a7e46fede6c490f1e68dff480678f7', 'active', false, 0, '2025-11-02 14:10:10', '', 'https://www.facebook.com/ngo.thao3', 'https://www.linkedin.com/in/ngophuongthao/', 'https://fptsoftware.com/', 'Hà Nội', 'Open 8', 'approved', true) ON CONFLICT (email) DO NOTHING;
