INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('A7yRRBy', 'Lương Hữu Phú Lộc', 'luonghuuphuloc@gmail.com', 'CEO (Co-founder)', 'CÔNG TY TNHH VIIS', 'Nông nghiệp công nghệ cao', '- Kinh nghiệm khởi nghiệp từ đại học
- Quá trình xây dựng một sản phẩm công nghệ và bán ra thị trường
- Nông nghiệp, nông nghiệp công nghệ cao', '- Quản lý rủi ro và đầu tư tài chính
- Quản trị đội ngũ và vận hành doanh nghiệp
- Kinh tế vi mô - vĩ mô và những mối quan hệ chính trị', 'Tôi đến với ABG khi trước mắt là sự bế tắc của hành trình khởi nghiệp
Tôi ở lại với ABG khi bên cạnh là những người anh em, bạn bè luôn sẵn sàng dang rộng vòng tay chào đón
Tôi ủng hộ ABG vì ở đó giá trị tốt đẹp của chúng ta sẽ được lan toả', 'https://storage.tally.so/private/KTKT2253.jpg?id=j97Q06&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6Imo5N1EwNiIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1OTU0MzQxNX0.4_hMVxDaga8Nj4sED0WrMrRHAQv12lQzEBau0pVsqXQ&signature=ffe5582aeca882d4e15370982a12a0e319a4039379d2c49fffeaa79d10f4219b', 'active', false, 0, '2025-10-03 10:42:14', '+84906515105', '', 'https://www.linkedin.com/in/luonghuuphuloc/', 'https://www.facebook.com/VietnameseIoTSolutions', 'Đà Lạt', 'Open 8', 'approved', true) ON CONFLICT (email) DO NOTHING;
INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('0Qa0lQj', 'Phan Nguyễn Nguyên Hương', 'pnhuongatwork@gmail.com', 'Chuyên viên', 'APLAS Vietnam (Reifenhauser Group)', 'Hành chính - Nhân sự', '1. Giao tiếp và đồng hành cùng trẻ từ 0-15 tuổi (trẻ dễ tổn thương, trẻ có nhu cầu đặc biệt, trẻ hòa nhập v.v)
2. Tổ chức trại hè quốc tế, dự án quốc tế NPO/NGO, chương trình CSR 
4. Chia sẻ văn hóa và tinh thần ABG, dẫn dắt và kết nối với cộng đồng ABG Alumni 
5. Vượt qua khủng hoảng, biến cố', '1. Quản lý tài chính cá nhân 
2. Ứng dụng AI trong công việc 
3. Nâng cao sức khỏe tinh thần 
4. Cầu lông, bơi, cờ vây', 'ABG là một hành trình quan trọng và ý nghĩa đối với em trên hành trình trưởng thành tinh thần và tìm kiếm những điều ý nghĩa trong cuộc sống thông qua giáo dục, công việc, cộng đồng và mối quan hệ tích cực. Rất vui vì được là một phần của nhà chung ABG, luôn sẵn lòng đóng góp vì một ABG Alumni tốt hơn. 

Chúc học viên và tân alumni nhận được nhiều giá trị tại ABG. "Chúng ta sinh ra không chỉ vì mình" hãy tin rằng cho đi chắc chắn sẽ được nhận lại, những món quà sẽ tương xứng với mức độ dấn thân và mở lòng của bạn.', 'https://storage.tally.so/private/z6818301642006_3070abb1fd981a049d3c430db7f276b9.jpg?id=OBJGa7&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6Ik9CSkdhNyIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1OTU0MzQxNX0.UPo565Fmb68YWtVKZVQGrBRLnsX0FzgmuEg0ViFW2pU&signature=74e0a46883fb39d50cc7fcc9ab049c2e0314895bef6cee89d95e89766de42538', 'active', false, 0, '2025-10-03 10:08:45', '+84974270155', '', 'https://www.linkedin.com/in/pnh230', 'https://vn.linkedin.com/company/allianceplastic', 'TPHCM', 'Open 9', 'approved', true) ON CONFLICT (email) DO NOTHING;
