INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('zxLJo18', 'Lê Minh Khoa', 'leminhkhoa2910@gmail.com', 'Analyst', 'Vietnam Investments Group', 'Đầu Tư', '1. Thể thao & sức khỏe
Cách duy trì thói quen chạy bộ, ăn uống, ngủ nghỉ lành mạnh.
Chia sẻ trải nghiệm từ những lần chạy đường dài (marathon, trail) và mindset “từng bước nhỏ” áp dụng vào cuộc sống.

2. Xây dựng mối quan hệ cá nhân & cộng đồng
Cách tạo được sự gắn kết bền vững với bạn bè, gia đình, người thân.
Những “nghi thức nhỏ” giúp giữ lửa kết nối (vd: weekly call với người thân, monthly dinner với bạn cũ).

3. Hành trình phát triển bản thân ngoài công việc
Một sở thích cá nhân (đọc sách, chơi nhạc, nấu ăn, thiền, đi du lịch khám phá).
Điều học được từ hoạt động này về sự kiên nhẫn, sáng tạo hay cân bằng trong cuộc sống.', '1. Chuyên môn/Kỹ năng
Muốn học thêm về Data-driven decision making: cách dùng dữ liệu để không chỉ phân tích mà còn dự đoán và ra quyết định chiến lược.

2. Cá nhân/Sức khoẻ
Muốn duy trì và nâng cao khả năng chạy bộ đường dài 🏃: không chỉ để giữ sức khỏe mà còn rèn luyện sự kiên trì và kỷ luật.

3. Quan hệ/Gia đình
Muốn học thêm cách xây dựng mối quan hệ sâu và bền: lắng nghe nhiều hơn, hiểu cách đặt câu hỏi tốt, và giữ kết nối ý nghĩa với cả bạn bè, đồng nghiệp lẫn gia đình.', '', 'https://storage.tally.so/private/Chan-Dung-The-Trang-4x6-4957.jpeg?id=5qzxpd&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjVxenhwZCIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1OTI0NTc3NH0.RsvIhZEkOyBnpVfjGYztAZk_CVcbcTQ05nqkBmBpzsE&signature=adc1ec3f8b8dc8dafd22861611fe62d39254bc2482dfac1c550a62941dbf348e', 'active', false, 0, '2025-09-30 11:11:19', '', 'https://www.facebook.com/khoa.le.788872/', 'https://www.linkedin.com/in/lekhoateddy/', 'https://vigroup.com/', 'TPHCM', 'Future Leaders 2', 'approved', true) ON CONFLICT (email) DO NOTHING;
