INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('PdGyy21', 'Lý Minh Nhật', 'ganuongphap@gmail.com', 'Một người bạn và một khái niệm', 'Quả Cầu', 'Quả Cầu là gì tuỳ thuộc vào nhu cầu của bạn', '- Hợp tác:
    - Thúc đẩy đối thoại
    - Chia sẻ kho tri thức của mình cho mọi người
    - Tiếp cận cho người khuyết tật
    - Xây dựng mạng lưới đối tác, các bên liên quan. Kết nối nguồn lực nhàn rỗi
- Nghiên cứu:
    - Minh hoạ, sơ đồ hóa kiến thức
    - Nghiên cứu cộng đồng mạng
    - Phân tích dữ liệu định lượng
    - Quản lý trích dẫn
    - Phân tích dữ liệu định tính
    - Nghiên cứu người dùng, phát triển sản phẩm
    - Nắm bắt xu hướng mạng
    - Tra lại lịch sử ghi chép
    - Tổng quan nghiên cứu. Tải bài
    - Viết bài
    - Xuất bản nghiên cứu
    - Tạo biểu đồ dữ liệu
- Vận hành:
    - Cập nhật thông tin bên ngoài, tổng hợp sự kiện sẽ diễn ra
    - Hậu cần các buổi họp, trò chuyện, sự kiện
    - Nhìn tổng thể, toàn cảnh kế hoạch
    - Hướng dẫn, đào tạo kiến thức, kỹ năng cho người mới
    - Quản lý tiền, kế toán
    - Thông tin, truyền thông ra bên ngoài
    - Nắm bắt hoạt động của nhau
    - Xây dựng thương hiệu, mối quan hệ
- Khác:
    - Phát triển cộng đồng
    - Xây dựng kho tri thức, hệ thống quản lý kiến thức hoặc quản lý dự án

Bài chi tiết: https://doi-thoai.deno.dev/qh.3yOOK4.1', 'Điều mình muốn học hỏi nhất là chính bạn', 'Nơi cuối trời nằm ngay trong tầm mắt
Tuy xa xôi nhưng muốn đến là được
Nhớ đem theo bia rượu hay đồ nhắm
Ra đó ngồi tha hồ ngắm nhân gian

Tại nơi ấy quá khứ gặp tương lai
Những hồi tưởng ùa về trong tiềm thức
Bốn mùa, buồn vui, tuổi thơ, chiếc lá
Ta gặp lại tất cả ở một nơi.', 'https://storage.tally.so/private/2021.jpg?id=GJN8je&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IkdKTjhqZSIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1ODg1NDMyOX0.R1yAC9NCEL11Wql9D4I53v1pGslzTmsIBYNV87f2Jeo&signature=8b5b112ae29452b3b6f6df97911687375c2afb63c4c85cffe61d39719ad3eea9', 'active', false, 0, '2025-09-25 02:59:22', '', 'https://www.facebook.com/qua.cau.the.sphere', 'https://www.linkedin.com/in/nh%E1%BA%ADt-l%C3%BD/', 'https://doi-thoai.deno.dev/truyen-ngu-ngon-ve-nhung-nguoi-mong-doi.3yOOK4.1', 'TPHCM', 'Open Special', 'approved', true) ON CONFLICT (email) DO NOTHING;
