- Tổ chức sự kiện 
- Quản lý dự án', '- Kỹ năng phản biện 
- Thiết kế chương trình giáo dục', '', 'https://storage.tally.so/private/515728170_2759852357544053_7545156193581233594_n.jpg?id=g7R9ON&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6Imc3UjlPTiIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1ODcyOTQ3NX0.RbwmWCsIJe5oeaAEdljk4rp3EHR6UgYRzQfMK72taQw&signature=0085a5189d071b977f7b98ac6a4e8365abe1322b0016127d4972d3abf3bbae5e', 'active', false, 0, '2025-09-24 04:20:39', '', 'https://www.facebook.com/hoangca.phung', 'https://www.linkedin.com/in/caphung/', 'https://www.linkedin.com/company/fpt-education-global/posts/?feedView=all', 'Đà Nẵng', 'Edu 4', 'approved', true) ON CONFLICT (email) DO NOTHING;
INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('dWk87Wy', 'Le Trung Kien', 'letrungkien.forwork@gmail.com', 'Sinh viên', 'Singapore Management University', 'Giáo dục', '1. Hồ sơ học bổng (thường cho con các anh chị alumni)
2. Việc làm tại Singapore (thường cho các bạn trẻ)', '1. Định hướng phát triển sự nghiệp
2. Xây dựng mối quan hệ
3. Cùng học hỏi thêm các bộ môn thể thao/nghệ thuật/ngôn ngữ mới', 'Em chào thầy cô, anh chị và các bạn. Em là Kiên - cựu học viên khoá ABG Edu4.

Hiện em đang học Thạc sĩ CNTT trong Doanh nghiệp (IT in Business) tại SMU (Singapore). Em tin tưởng vào tầm nhìn đào tạo lãnh đạo trẻ của ABG; và tin rằng những nguồn vốn xã hội tại ABG Alumni sẽ có thể giúp đỡ được em trong hành trình trở thành lãnh đạo trẻ trong tương lai gần.

Em mong có thể trở thành nhân tài (rare talent) để đóng góp tích cực vào sự phát triển của các cộng đồng mà em thuộc về; từ đó vừa đảm bảo cuộc sống thoải mái cho bản thân và gia đình; vừa nhìn thấy được tác động tích cực của mình tới xã hội. Hiện tại em đang theo đuổi lĩnh vực công nghệ và tư vấn chuyển đổi số như là phương tiện để đạt được mục tiêu trên.

Em tin rằng các cơ hội lớn sẽ tới từ con người chứ không phải LinkedIn hay Trang tuyển dụng. Em mong sớm được học hỏi thêm từ các anh chị.', 'https://storage.tally.so/private/Passport-Photo.jpg?id=b809Q2&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6ImI4MDlRMiIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1ODcyOTQ3NX0.vXL4Zk_QuX0rLWl009AjymncDY3BXShVHKYjQjmO9wE&signature=de0bc40b3df8bafa6501a558ee9dae4ac624b6b3c6bdd57422d44bd358c01d1a', 'active', false, 0, '2025-09-24 03:52:58', '+84868456702', '', 'https://www.linkedin.com/in/neikgnurtel/', 'http://smu.edu.sg/', 'Singapore', 'Edu 4', 'approved', true) ON CONFLICT (email) DO NOTHING;
INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('eqY0Oko', 'Vũ Thanh Hà', 'havt.abg@gmail.com', 'Giám đốc điều hành', 'Trung tâm khám phá khoa học Einstein House', 'Giáo dục STEM', '- Kinh nghiệm về triển khai các hoạt động Stem, khoa học (setup không gian trải nghiệm, tổ chức ngày hội khoa học, cuộc thi,...)
- Kinh nghiệm làm việc với các trường học
- Kết nối với các chuyên gia', 'Phát triển network trong lĩnh vực và trong ngành giáo dục
Nắm bắt thông tin, xu hướng, các vấn đề vĩ mô
Tìm kiếm những ý tưởng đột phá, học hỏi cách thức thực thi', 'Mình là người khá cởi mở, luôn sẵn sàng chia sẻ những ý tưởng, dự định mà mình sẽ triển khai. Trong ngắn hạn mình mong muốn đưa việc thực hành khoa học trở nên phổ cập hơn với các nhà trường. Các em học sinh không còn phải học chay thuần lý thuyết rồi giải bài tập như ngày trước mà được học thông qua thực hành, được tự làm, tự rút ra kiến thức và ứng dụng nó', 'https://storage.tally.so/private/Anh-ca-nhan.jpg?id=2JMXx9&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjJKTVh4OSIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1ODcyOTQ3NX0.PTCTdcWAWcIK8qMKXNzJMRTj8ptL29hUT8TPLP5FigM&signature=42738e412fc410aa3a2f77f2207cf09705c6dd0b72a078f565635ec9358f0e91', 'active', false, 0, '2025-09-24 03:22:05', '+84902068896', '', '', 'https://www.facebook.com/EH.EveryChildAGenius', 'Hà Nội', 'Open 1', 'approved', true) ON CONFLICT (email) DO NOTHING;
