INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('QKOzxMl', 'Nguyễn Thu Thủy', 'thuthuy12.205@gmail.com', 'Product Marketing', 'FPT software, STEAM FOR VIETNAM', 'Product Marketing', 'Ít nhất 3 điều em sẵn sàng chia sẻ cho ABG Alumni:

Kinh nghiệm 3 năm tham gia và đóng góp cho các hoạt động giáo dục cộng đồng – từ việc tổ chức, triển khai dự án đến lan tỏa giá trị học tập cho học sinh, sinh viên.

Hành trình chuyển hướng sang lĩnh vực công nghệ và phát triển sản phẩm, với mong muốn tạo ra những giải pháp mang tính ứng dụng, phục vụ cộng đồng và đặc biệt là giáo dục.

Góc nhìn về kết nối và xây dựng các sáng kiến vì cộng đồng, cách kết hợp giữa đam mê cá nhân với nhu cầu xã hội để tạo ra giá trị bền vững.', 'Ít nhất 3 điều em đang muốn học hỏi thêm:

Kiến thức và góc nhìn về chính sách công – để hiểu rõ hơn cách hệ thống vận hành, từ đó có thể kết nối và đóng góp hiệu quả hơn cho các hoạt động cộng đồng và giáo dục.

Kinh nghiệm khởi nghiệp và xây dựng mô hình bền vững – nhằm học cách đưa một ý tưởng từ giai đoạn thử nghiệm đến triển khai thực tế, đặc biệt trong các sáng kiến xã hội.

Tư duy và công cụ đổi mới sáng tạo – để phát triển những giải pháp sáng tạo, ứng dụng công nghệ hiệu quả vào giải quyết các vấn đề của cộng đồng.', '', 'https://storage.tally.so/private/Screenshot-2025-07-25-224220.png?id=LJQ1G2&accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IkxKUTFHMiIsImZvcm1JZCI6IjN5T09LNCIsImlhdCI6MTc1ODcyOTQ3NX0.-xANKki42750yvg65tbG_xLADAxqXdkN66UzRVFCOlw&signature=1cde3215a787813211395fba67596b00667cd01c1094c4b7296f86f88932a8e6', 'active', false, 0, '2025-09-24 01:57:12', '', 'https://www.facebook.com/thuthuyng1210', 'https://www.linkedin.com/in/thuthuyng1205/', 'https://www.linkedin.com/in/thuthuyng1205/', 'Hà Nội', 'Future Leaders 1', 'approved', true) ON CONFLICT (email) DO NOTHING;
