INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('1ApMOo1', 'Lê Thị Kim Ngân', 'nganwildlife@gmail.com', 'Education and Outreach Coordinator (main) and Community Engagement Coordinator', 'Save Vietnam''s Wildlife', 'NPO - Bảo tồn tài nguyên thiên nhiên', 'kinh nghiệm với chương trình giáo dục trường học và kết nối cộng đồng về lĩnh vực, thông tin trải nghiệm và kết nối với các VQG/KBT', 'mindfulness, quản lý và đánh giá dự án, kết nối chuyên môn và nguồn hỗ trợ đến học sinh/ các trường học khó khăn thuộc vùng đệm các VQG/KBT, các dự án sinh kế và hỗ trợ cộng đồng', 'Ngân tập trung vào sứ mệnh giảm các hành vi tác động đến động vật hoang dã và bảo tồn tài nguyên thiên nhiên tại Việt Nam bằng cách tiếp cận cộng đồng. Với hơn 12 năm duy nhất 1 lĩnh vực (có mở rộng tương ứng với định hướng chiến lược mảng hđ), Ngân có kinh nghiệm về giáo dục bảo tồn trong trường học (lồng ghép vào các chương trình sinh hoạt ngoại khóa), các chương trình sự kiện (chính phủ, phi chính phủ, người dân, học sinh-sinh viên), chiến dịch thay đổi hành vi dựa vào truyền thông, thúc đẩy du lịch sinh thái (gắn với sinh kế cộng đồng). Ngân có kết nối sâu với VQG Cúc Phương - Pù Mát - Cát Tiên - U Minh Thượng - U Minh Hạ - KBT Thiên nhiên - Văn hóa Đồng Nai; kết nối và tư vấn cho các VQG/KBT tại Việt Nam (nhiều hơn với miền Trung và miền Nam); các chuyên gia trong cùng lĩnh vực. Ngân hy vọng có thể kết nối để tạo nhiều cơ hội hơn cho cộng đồng vùng đệm tại các VQG/KBT, những người rất quan trọng trong việc bảo vệ rừng - động vật hoang dã - nguồn tài nguyên thiên nhiên chung của Việt Nam, từ đó giúp họ được an tâm hơn và quyết tâm hơn trong việc ra quyết định không sử dụng - săn bắt - tiếp tay và hành động mạnh mẽ hơn để bảo vệ bền vững thiên nhiên.', 'https://ketrmymhnrtkiygjbtye.supabase.co/storage/v1/object/public/avatar/le%20ngan_edu.png', 'active', false, 0, '2025-09-23 05:04:28', '+84823582736', '', 'linkedin.com/in/ngan-le-716309147', 'https://svw.vn/vi/', 'TPHCM', 'Edu 2', 'approved', true) ON CONFLICT (email) DO NOTHING;
INSERT INTO members (id, name, email, role, company, expertise, can_help_with, looking_for, bio, avatar_url, status, paid, free_requests_used, created_at, phone, facebook_url, linkedin_url, company_website, country, abg_class, approval_status, is_csv_imported) VALUES ('yPdxj06', 'Nguyễn Hồ Mạnh Khang', 'nguyenhomanhkhang@gmail.com', 'Chief of Staff', 'PITO - AI Catering Platform', 'Catering Platform', '(1) Marketing Strategy cho startup với ngân sách và nguồn lực hạn chế. 
(2) Hoạt động sáng tạo Internal Communication và People Engagement. 
(3) Quản trị nhân sự Gen Z - cách chia sẻ và cùng phát triển.', '(1) Cách xây dựng SOPs theo từng giai đoạn phát triển của business. 
(2) Lộ trình phát triển nhân sự hiệu quả về cả chuyên môn và kỹ năng. 
(3) Học hỏi cách làm hay về quản trị con người và cảm xúc.', 'Xin chào! Mình là Mạnh Khang, đang đảm nhận vai trò Chief of Staff tại PITO - một startup tiên phong trong lĩnh vực Catering Platform tại Việt Nam.

Khang may mắn được đồng hành cùng công ty qua nhiều giai đoạn phát triển từ năm 2020 đến nay, tích lũy những bài học thực tế quý giá về việc xây dựng và vận hành startup.

Với background từ ngành Báo chí và Truyền thông (ĐH KHXH&NV, ĐHQG TP.HCM), Khang từng trải nghiệm các vai trò phóng viên, truyền thông giáo dục và doanh nghiệp trước khi chuyển hướng sang lĩnh vực hiện tại.

Là người được bạn bè đánh giá là cởi mở và dễ gần, Khang hy vọng sẽ đóng góp những giá trị thiết thực cho cộng đồng ABG Alumni và cùng nhau học hỏi, phát triển.', 'https://in.pito.vn/wp-content/uploads/2025/09/Avatar-Manh-Khang-PITO.webp', 'active', false, 0, '2025-09-23 04:36:00', '', 'https://www.facebook.com/nguyenhomanhkhang', 'https://www.linkedin.com/in/nguyenhomanhkhang/', 'https://pito.vn/', 'TPHCM', 'Open 8', 'approved', true) ON CONFLICT (email) DO NOTHING;
